   295	    private Response checkPreconditions(S3Object obj, String ifMatch, String ifNoneMatch,
   296	                                         String ifModifiedSince, String ifUnmodifiedSince) {
   297	        String eTag = obj.getETag();
   298	        Instant lastModified = obj.getLastModified();
   299	
   300	        if (ifMatch != null && !eTagMatches(ifMatch, eTag)) {
   301	            return preconditionFailedResponse();
   302	        }
   303	
   304	        if (ifUnmodifiedSince != null && ifMatch == null) {
   305	            Instant since = parseHttpDate(ifUnmodifiedSince);
   306	            if (since != null && lastModified.isAfter(since)) {
   307	                return preconditionFailedResponse();
   308	            }
   309	        }
   310	
   311	        if (ifNoneMatch != null && eTagMatches(ifNoneMatch, eTag)) {
   312	            return notModifiedResponse(eTag, lastModified);
   313	        }
   314	
   315	        if (ifModifiedSince != null && ifNoneMatch == null) {
   316	            Instant since = parseHttpDate(ifModifiedSince);
   317	            if (since != null && !lastModified.isAfter(since)) {
   318	                return notModifiedResponse(eTag, lastModified);
   319	            }
   320	        }
   321	
   322	        return null;
