import java.net.URLEncoder;
import java.net.URLDecoder;
import java.nio.charset.StandardCharsets;

class TestCopy {
    public static void main(String[] args) {
        // Simulate what boto3 would send
        String key = "src/テスト画像.png";
        // boto3's quote uses safe='/' by default
        String encodedKey = URLEncoder.encode(key, StandardCharsets.UTF_8)
                .replace("+", "%20")
                .replace("%2F", "/");
        System.out.println("Encoded key (boto3-style): " + encodedKey);

        // Full copy source header
        String copySource = "/test-bucket/" + encodedKey;
        System.out.println("Copy source header: " + copySource);

        // What handleCopyObject does now:
        String source = copySource.startsWith("/") ? copySource.substring(1) : copySource;
        int slashIndex = source.indexOf('/');
        String sourceBucket = source.substring(0, slashIndex);
        String sourceKey = source.substring(slashIndex + 1);
        System.out.println("Extracted sourceKey (current): " + sourceKey);
        System.out.println("Matches original? " + sourceKey.equals(key));

        // After fix - URL decode:
        String decodedSource = URLDecoder.decode(copySource, StandardCharsets.UTF_8);
        source = decodedSource.startsWith("/") ? decodedSource.substring(1) : decodedSource;
        slashIndex = source.indexOf('/');
        sourceBucket = source.substring(0, slashIndex);
        sourceKey = source.substring(slashIndex + 1);
        System.out.println("Extracted sourceKey (after fix): " + sourceKey);
        System.out.println("Matches original? " + sourceKey.equals(key));
    }
}
JAVAEOF
