                    .header("ETag", obj.getETag())
                    .header("Last-Modified", RFC_822.format(obj.getLastModified()))
                    .header("Accept-Ranges", "bytes");
            if (obj.getVersionId() != null) {
                resp.header("x-amz-version-id", obj.getVersionId());
